#include <stdio.h>
#include <yara.h>

int main() {
    yr_initialize();

    YR_COMPILER* compiler = NULL;
    YR_RULES* rules = NULL;

    yr_compiler_create(&compiler);

    const char* rule_str = "rule test { strings: $a =/abc([^\"\\\\])*\"/ nocase condition: $a }";

    if (yr_compiler_add_string(compiler, rule_str, NULL) != 0) {
        printf("Failed to compile rule\n");
        return 1;
    }

    yr_compiler_get_rules(compiler, &rules);

    uint8_t blob[] = "abc\xE0\x22";
    size_t len = sizeof(blob) - 1;  // exclude null terminator

    printf("Testing blob: ");
    for (size_t i = 0; i < len; i++) {
        printf("%02x ", blob[i]);
    }
    printf("\n");

    int matches = 0;
    int scan_result = yr_rules_scan_mem(rules, blob, len, 0, NULL, &matches, 0);

    printf("Scan result: %d, matches: %d\n", scan_result, matches);

    yr_rules_destroy(rules);
    yr_compiler_destroy(compiler);
    yr_finalize();

    return 0;
}
EOF
